// Seeded PRNG so the bookings are identical on every load (stable snapshots).
var __seed = 0x99ab2c5d
function rand() {
  __seed |= 0
  __seed = (__seed + 0x6d2b79f5) | 0
  var t = Math.imul(__seed ^ (__seed >>> 15), 1 | __seed)
  t = (t + Math.imul(t ^ (t >>> 7), 61 | t)) ^ t
  return ((t ^ (t >>> 14)) >>> 0) / 4294967296
}

function generateTimeRangeData(label, startDate, endDate, count) {
  var points = [] // random points between start and end date
  var series = [] // series between points 1 and 2, 3 and 4 etc

  // Generate random points
  for (var i = 0; i < count; i++) {
    points.push(
      new Date(
        startDate.getTime() +
          rand() * (endDate.getTime() - startDate.getTime()),
      ),
    )
  }

  // Sort the points in ascending order
  points.sort((a, b) => a - b)

  // Create ranges
  for (var i = 0; i < points.length; i += 2) {
    if (i + 1 < points.length) {
      var startDateTime = points[i]
      var endDateTime = points[i + 1]
      series.push({
        x: label,
        y: [startDateTime.getTime(), endDateTime.getTime()],
      })
    }
  }

  return series
}

